import React from 'react'
import styled from 'styled-components'
import video from './static/prada_2021_menswear.webm'


const BlendBackground = styled.div `
background-color:rgba(0, 0, 0, 0.3);
width:100vw;
height:500px;
position:absolute;
z-index:1;
`

const BannerVideo = styled.video `
margin-top:-150px;
`
const Title = styled.div `
font-size:2.2rem;
color:white;
font-weight:bold;
z-index:2;
`

const Content = styled.p `
font-size:1.8rem;
color:white;
z-index:2;
`

const ButtonWrapper = styled.div `
z-index:2;
`

const MensWear = styled.button `
border:1px solid white;
padding:10px 15px;
width:18vw;
height:10vh;
background-color:transparent;
border-radius:4px;
font-size:1.2rem;
color:white;
&:hover {
	background-color:white;
	cursor:pointer;
	color:#1C1C1C;
}
`

const WomensWear = styled.button `
border:1px solid white;
padding:10px 15px;
width:18vw;
margin-left:40px;
height:10vh;
background-color:transparent;
border-radius:4px;
font-size:1.2rem;
color:white;
&:hover {
	background-color:white;
	cursor:pointer;
	color:#1C1C1C;
}
`

const Div = styled.div `
overflow:hidden;
height:550px;
position:relative;
`

const BannerWrapper = styled.div `
position:absolute;
display:flex;
flex-direction:column;
justify-content:center;
align-items:center;
z-index:5;
`

export default function Banner () {


	return (
		<Div>
			<BannerVideo autoPlay={'autoplay'} muted playsinline loop width='100%'>

			<BannerWrapper>
				<Title>Ultimate Platform for Your Designer Clothing</Title>
				<Content>Sell today</Content>
				<ButtonWrapper>
					<MensWear>Shop MENSWEAR</MensWear>
					<WomensWear>Shop WOMENSWEAR</WomensWear>
				</ButtonWrapper>
				<BlendBackground />
			</BannerWrapper>


			<source  src={video}  type='video/webm'/>
			</BannerVideo>
		</Div>

	)
}
